我知道你很急，但是你先别急。就像是学编程语言第一件事是写“Hello, World!”一样，复健当然也可以从这里开始。 #include <iostream>
using namespace std;

int main() {
    cout << "Hello, World!" << endl;
    return 0;
} 不过机考时，可以用下面这个版本： #include <bits/stdc++.h>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    cout << "Hello, World!" << endl;
    return 0;
} #include <bits/stdc++.h> 是算法题里常见的“全家桶”头文件，能省掉很多按需引入标准库的时间；ios::sync_with_stdio(false); 和 cin.tie(nullptr); 用来加速输入输出。我在练习时尽量不用这个写法，以免忘记需要 #include 什么头文件。

为了让手动起来，先写一个最普通的问题：读入 n 个整数，输出它们的和、最大值和最小值。 #include <iostream>
#include <vector>
using namespace std;

int main(){
    int n;
    cin >> n;
    vector<int> arr(n);
    for(int i = 0; i < n; i++){
        cin >> arr[i];
    }
    long long sum = 0;
    int min = arr[0];
    int max = arr[0];
    for(int i = 0; i < n; i++){
        sum += arr[i];
        if(arr[i] < min){
            min = arr[i];
        }
        if(arr[i] > max){
            max = arr[i];
        }
    }
    cout << "Sum: " << sum << '\n';
    cout << "Min: " << min << '\n';
    cout << "Max: " << max << '\n';
    return 0;
} 这题本身当然不难，但它可以提醒我几件事： 求和最好用 long long，避免整数范围不够。初始化最大值和最小值时，可以直接用第一个元素。输出换行用 '\n'，不要在大量输出里滥用 endl。能用范围 for 的时候，代码会清爽很多。

先从取地址开始。 #include <iostream>
using namespace std;

int main() {
    int x = 42;

    cout << x << '\n';
    cout << &x << '\n';

    return 0;
} &x 取到的是 x 的地址。指针变量可以保存这个地址，再通过解引用访问它指向的对象。 int x = 42;
int* p = &x;

*p = 100; // x == 100 这里几个符号的含义是： &x：取 x 的地址。int* p：p 是指向 int 的指针。*p：访问 p 指向的对象。p + 1：移动到下一个 int 的位置，不是地址数值简单加 1。 函数参数如果按值传递，只会修改副本；如果传地址，就能修改外部对象。 void inc(int* p) {
    (*p)++;
}

int x = 0;
inc(&x); // x == 1 这里必须写 (*p)++。

现代 C++ 用 nullptr 表示空指针。 int* p = nullptr;

if (p != nullptr) {
    cout << *p << '\n';
} 空指针可以比较，不能解引用。 野指针一般来自两类情况。第一种是未初始化： int* p;     // 未初始化
*p = 10;    // UB 第二种是指向已经失效的位置，比如返回局部变量地址： int* bad() {
    int x = 10;
    return &x; // 返回局部变量地址
} 指针声明时初始化，不知道指向谁就设为 nullptr。解引用前确认指针有效。不返回局部变量地址。能用引用或容器时，不为了“像 C”而手写裸指针。

数组名在很多表达式里会退化为指向首元素的指针。 int a[3] = {10, 20, 30};

cout << *a << '\n';       // 10
cout << *(a + 1) << '\n'; // 20
cout << a[2] << '\n';     // 30 a[i] 可以理解成 *(a + i)。但数组不是指针本身： int a[3] = {10, 20, 30};
int* p = a;

cout << sizeof(a) << '\n'; // 3 * sizeof(int)
cout << sizeof(p) << '\n'; // sizeof(int*) 函数参数里的数组比较特殊： void f(int a[]) {
    cout << sizeof(a) << '\n'; // 这里 a 已经是 int*
} 也就是说，数组作为函数参数时会退化成指针，长度信息会丢掉。机考里如果没有特殊需求，我还是优先用 vector，省掉手动传长度和越界风险。

非常适合拿来折磨人。 指针数组：本质是数组，数组里的每个元素都是指针。 int a = 1;
int b = 2;
int c = 3;

int* p[3] = {&a, &b, &c};

cout << *p[0] << '\n'; // 1 p 先和 [3] 结合，所以 p 是一个数组；数组元素类型是 int*。 数组指针：本质是指针，指向一个数组。 int arr[3] = {1, 2, 3};

int (*p)[3] = &arr;

cout << (*p)[0] << '\n'; // 1
cout << (*p)[2] << '\n'; // 3 这里括号不能省。如果写成： int* p[3]; 那就是指针数组；写成： int (*p)[3]; 才是数组指针。 数组指针如果作为函数返回值，声明会更难认： int (*getArray())[3] {
    static int arr[3] = {1, 2, 3};
    return &arr;
} 这里 getArray 是一个函数，它返回 int (*)[3]，也就是“指向含 3 个 int 的数组的指针”。调用时可以这样写： int (*p)[3] = getArray();

cout << (*p)[0] << '\n'; 这种声明可读性比较差。实际写 C++ 时可以用 using 起别名： using IntArray3 = int[3];

IntArray3* getArray() {
    static int arr[3] = {1, 2, 3};
    return &arr;
} 这样就清楚很多：getArray 返回的是 IntArray3*。

引用可以理解成对象的别名。它声明时必须绑定，之后不能改绑。 int x = 42;
int& r = x;

r = 100; // x == 100 引用传参可以替代很多“传指针进去改外部变量”的写法： void inc(int& x) {
    x++;
}

int a = 0;
inc(a); // a == 1 和指针传参对比： void inc1(int* p) { (*p)++; }
void inc2(int& x) { x++; }

inc1(&a);
inc2(a); 引用版本更像普通变量，调用点也更干净；指针版本则能显式表达“可能为空”“可能改指向”等语义。机考里的普通修改参数，引用通常更顺。 作为练习，我手写了两个版本的 swap。 引用版本： void swap(int& a, int& b) {
    int t = a;
    a = b;
    b = t;
} 指针版本： void swap(int* a, int* b) {
    int t = *a;
    *a = *b;
    *b = t;
} 调用点区别也很清楚： int x = 1;
int y = 2;

swap(x, y);   // 引用版本
swap(&x, &y); // 指针版本 当然真正写题时直接用标准库： swap(a, b);

范围 for 默认按值拷贝。 vector<int> a = {1, 2, 3};

for (int x : a) {
    x *= 2;
}

// a 仍然是 {1, 2, 3} 要修改原容器元素： for (int& x : a) {
    x *= 2;
} 只读且避免拷贝： for (const string& s : names) {
    cout << s << '\n';
} 这里的判断可以简单一点： 小类型只读：int x需要修改：T& x大对象只读：const T& x

const T& 是 C++ 函数参数里非常常见的写法：避免拷贝，同时承诺不修改。 long long sum(const vector<int>& a) {
    long long ans = 0;
    for (int x : a) {
        ans += x;
    }
    return ans;
} 如果写成： long long sum(vector<int> a) 会复制整个 vector。数据量一大，这种拷贝没有必要。 const 和指针放在一起时也需要恢复一下： const int* p1;       // 指向 const int，不能通过 p1 改值，p1 可改指向
int* const p2 = &x;  // const 指针，p2 不可改指向，可通过 p2 改值
const int* const p3 = &x; // 值和指向都不能改 读法技巧：从变量名开始往外读。p2 先遇到 const，说明指针本身 const；p1 指向的是 const int。

普通引用 T& 是左值引用，通常绑定到有名字的对象。 int x = 10;
int& r = x; 非常量左值引用不能绑定临时值： int& r = 10; // error 但 const T& 可以绑定临时值： const int& r = 10; 右值引用写作 T&&： int&& r = 10; 它主要服务于移动语义和完美转发。机考里通常不需要手写复杂右值引用，但至少要能区分： if (a && b) { } // 逻辑与

int&& x = 10;  // 右值引用 同样是 &&，一个在表达式里，一个在类型里。

引用折叠主要在模板里出现。 template <typename T>
void f(T&& x) {
} 这里的 T&& 在模板推导中不一定是右值引用。折叠规则： &  + &  -> &
&  + && -> &
&& + &  -> &
&& + && -> && 记忆：只要有一个 &，结果就是 &；只有全是 &&，结果才是 &&。 这就是所谓 forwarding reference / universal reference 的基础。现阶段先能看懂，不展开 std::forward。

vector 可以理解成长度可变的数组。 #include <iostream>
#include <vector>
using namespace std;

int main() {
    vector<int> a;

    a.push_back(10);
    a.push_back(20);
    a.push_back(30);

    cout << a.size() << '\n';
    cout << a[0] << ' ' << a[1] << ' ' << a[2] << '\n';

    return 0;
} 常用操作先列一下： vector<int> a;：空 vector。vector<int> a(n);：长度为 n，元素默认初始化。vector<int> a(n, x);：长度为 n，每个元素初始化为 x。a.size()：元素个数。a.empty()：是否为空。a.push_back(x)：末尾加入元素。a.pop_back()：删除末尾元素。a.back()：最后一个元素。a.clear()：清空。 读入 n 个数时，最常见写法： int n;
cin >> n;

vector<int> a(n);
for (int i = 0; i < n; i++) {
    cin >> a[i];
} 如果不知道数量，或者边读边加： vector<int> a;
int x;

while (cin >> x) {
    a.push_back(x);
}

需要下标时，用普通 for： for (int i = 0; i < (int)a.size(); i++) {
    cout << i << ": " << a[i] << '\n';
} 不需要下标时，用范围 for： for (int x : a) {
    cout << x << '\n';
} 需要修改元素时，用引用： for (int& x : a) {
    x *= 2;
} 大对象只读时，用 const 引用： for (const string& s : names) {
    cout << s << '\n';
} 这里有一个小习惯：a.size() 的类型是 size_t，是无符号整数。机考里为了少和 signed / unsigned warning 纠缠，我通常会写： for (int i = 0; i < (int)a.size(); i++) {
} 或者干脆提前存下来： int n = a.size();
for (int i = 0; i < n; i++) {
}

排序需要 <algorithm>。 #include <algorithm> 升序： sort(a.begin(), a.end()); 降序： sort(a.begin(), a.end(), greater<int>()); 自定义排序： vector<pair<int, int>> a = {{1, 3}, {1, 2}, {2, 1}};

sort(a.begin(), a.end(), [](const auto& x, const auto& y) {
    if (x.first != y.first) return x.first < y.first;
    return x.second > y.second;
}); 这里 lambda 的意思是：先按第一维升序，第一维相同再按第二维降序。 查找某个值： auto it = find(a.begin(), a.end(), x);

if (it != a.end()) {
    cout << "found" << '\n';
} 如果 vector 已经有序，可以二分： bool ok = binary_search(a.begin(), a.end(), x); 找第一个大于等于 x 的位置： auto it = lower_bound(a.begin(), a.end(), x);
int pos = it - a.begin(); 这部分后面二分专题再细写，现在先恢复 API。

二维数组可以用二维 vector： int n, m;
cin >> n >> m;

vector<vector<int>> grid(n, vector<int>(m));

for (int i = 0; i < n; i++) {
    for (int j = 0; j < m; j++) {
        cin >> grid[i][j];
    }
} 初始化为某个值： vector<vector<int>> dist(n, vector<int>(m, -1)); 方向数组也很常见： int dx[4] = {1, -1, 0, 0};
int dy[4] = {0, 0, 1, -1};

for (int k = 0; k < 4; k++) {
    int nx = x + dx[k];
    int ny = y + dy[k];
} 二维 vector 写起来方便，但每一行本质上是单独的 vector，不是一整块连续的二维数组。一般机考不太需要关心这个，知道即可。

第一，[] 不检查越界。 vector<int> a(3);
cout << a[10] << '\n'; // UB 如果想检查越界，可以用： a.at(10) 第二，空 vector 不能直接 back() 或 pop_back()。 if (!a.empty()) {
    a.pop_back();
} 第三，遍历时修改 vector 大小要小心。 for (int i = 0; i < (int)a.size(); i++) {
    if (a[i] == 0) {
        a.push_back(1);
    }
} 这种代码可能导致循环范围不断变化。不是一定错，但要明确自己在干什么。

string 是 C++ 里的字符串类型。 #include <iostream>
#include <string>
using namespace std;

int main() {
    string s = "hello";

    cout << s.size() << '\n';
    cout << s[0] << '\n';

    return 0;
} 常用操作： s.size()：长度。s.empty()：是否为空。s[i]：第 i 个字符。s.push_back(c)：末尾加字符。s += t：拼接字符串。s.substr(pos, len)：截取子串。s.find(t)：查找子串。 例子： string s = "abcdef";

cout << s.substr(2, 3) << '\n'; // cde
cout << s.find("cd") << '\n';   // 2 find 找不到时会返回 string::npos： if (s.find("xy") == string::npos) {
    cout << "not found" << '\n';
}

cin >> s 会读到空白字符为止： string s;
cin >> s; 输入： hello world 这里只会读到 hello。 如果要读整行，用 getline： string line;
getline(cin, line); 但如果前面刚用过 cin >> n，换行符还留在输入缓冲区里，直接 getline 可能读到空行。 int n;
cin >> n;

string line;
getline(cin, line); // 可能读到上一行剩下的换行 常用处理： int n;
cin >> n;
cin.ignore();

string line;
getline(cin, line); 如果要更稳一点，可以写： #include <limits>
cin.ignore(numeric_limits<streamsize>::max(), '\n');

遍历字符： for (char c : s) {
    cout << c << '\n';
} 修改字符： for (char& c : s) {
    if ('a' <= c && c <= 'z') {
        c = c - 'a' + 'A';
    }
} 也可以用 <cctype>： #include <cctype>

for (char& c : s) {
    c = toupper(c);
} 注意 toupper 返回的是 int，赋回 char 一般没问题，但要知道它不是直接返回 char。

写一个简单练习：读入一整行，按空格切分，输出每个单词的长度。 #include <iostream>
#include <sstream>
#include <string>
#include <vector>
using namespace std;

int main() {
    string line;
    getline(cin, line);

    stringstream ss(line);
    string word;
    vector<int> lengths;

    while (ss >> word) {
        lengths.push_back(word.size());
    }

    for (int x : lengths) {
        cout << x << ' ';
    }
    cout << '\n';

    return 0;
} 这里顺手用到了 stringstream，它可以把一个字符串当成输入流来读。以后处理“一行里有多个元素”的输入时会很方便。

